- (BOOL)isLifetimeMemberWithExpireDate:(NSString *)expireDateString {
    if (!self.IsSVIP) {
        return NO;
    }
    // 创建临界日期
    static NSDate *criticalDate;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        NSDateComponents *comps = [[NSDateComponents alloc] init];
        comps.year = 2098;
        comps.month = 12;
        comps.day = 31;
        criticalDate = [[NSCalendar currentCalendar] dateFromComponents:comps];
    });

    // 转换传入的日期字符串
    static NSDateFormatter *formatter;
    static dispatch_once_t formatterToken;
    dispatch_once(&formatterToken, ^{
        formatter = [[NSDateFormatter alloc] init];
        formatter.dateFormat = @"yyyy-MM-dd";
    });
    NSDate *expireDate = [formatter dateFromString:expireDateString];

    if (!expireDate) {
        return NO;
    }
    return [expireDate compare:criticalDate] == NSOrderedDescending;
}

