   788	    dispatch_sync(manager.queue, ^{
   789	        // 先落掉进入后台前的前台时长，再保存后台快照，后续按时间差补算。
   790	        [manager accumulateElapsedUsageAtTime:now];
   791	        [manager persistUsageState];
   792	        NSTimeInterval appUsedTimeInSecond = [WBEventManager persistedPendingAppDuration];
   793	        NSTimeInterval vappUsedTimeInSecond = [WBEventManager persistedPendingVappDuration];
   794	        NSTimeInterval backgroundTime = [WBEventManager backgroundEnterTime];
   795	        
   796	        [WBEventManager saveBackgroundTrackingAtTime:now runningVapp:(currentVappId > 0) vappId:currentVappId];
   797	    });
   798	    // 旧逻辑：
   799	    // [WBEventManager addEventWithType:eventTypeAppEnterBackground];
   800	    // [[WBEventManager defaultManager] saveAsync];
   801	    [WBEventManager addEventWithType:eventTypeAppEnterBackground];
   802	    [manager saveAsync];
   803	    dispatch_async(dispatch_get_main_queue(), ^{
   804	        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppEnterBackground defaultHandler:nil];
   805	    });
   806	}
