   808	/// 进程结束前保存最后一个可观测区间，让下一次冷启动还能继续累计同一轮 heartbeat。
   809	+ (void)onAppWillTerminate {
   810	    WBEventManager *manager = [WBEventManager defaultManager];
   811	    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
   812	    dispatch_sync(manager.queue, ^{
   813	        // 保存进程结束前最后一段可观测时长，保证下次冷启动还能续上这轮 heartbeat。
   814	        if ([WBEventManager hasBackgroundEnterTime]) {
   815	            [manager applyBackgroundUsageAtTime:now];
   816	        } else {
   817	            [manager accumulateElapsedUsageAtTime:now];
   818	        }
   819	        [manager persistUsageState];
   820	    });
